  {
    "path": "windrose-trainer/Program.cs",
    "content": "using System;\nusing System.Collections.Generic;\nusing System.IO;\nusing System.Linq;\nusing WindroseTrainer.Core;\n\nnamespace WindroseTrainer\n{\n    /// <summary>\n    /// Entry point for the Windrose Trainer application.\n    /// Trains a wind rose model from directional wind data.\n    /// </summary>\n    class Program\n    {\n        static void Main(string[] args)\n        {\n            Console.WriteLine(\"Windrose Trainer v1.0\");\n            Console.WriteLine(\"=====================\\n\");\n\n            // Sample wind data: (speed, direction in degrees)\n            var windData = new List<(double Speed, double Direction)>\n            {\n                (5.2, 0),\n                (3.8, 45),\n                (6.1, 90),\n                (4.5, 135),\n                (7.3, 180),\n                (2.9, 225),\n                (8.0, 270),\n                (4.1, 315),\n                (5.5, 30),\n                (6.8, 120),\n                (3.3, 210),\n                (7.7, 300)\n            };\n\n            // Train the wind rose model\n            var trainer = new WindroseTrainerEngine();\n            var model = trainer.Train(windData, numSectors: 8);\n\n            // Display results\n            Console.WriteLine(\"Trained Wind Rose Model:\");\n            Console.WriteLine(model.ToString());\n\n            // Export to JSON\n            string json = model.ToJson();\n            File.WriteAllText(\"windrose_model.json\", json);\n            Console.WriteLine(\"\\nModel exported to windrose_model.json\");\n\n            // Generate a simple report\n            var reporter = new WindroseReporter();\n            string report = reporter.GenerateReport(model);\n            File.WriteAllText(\"windrose_report.txt\", report);\n            Console.WriteLine(\"Report saved to windrose_report.txt\");\n        }\n    }\n}\n"
  },
