    "path": "windrose-trainer/Core/WindroseTrainerEngine.cs",
    "content": "using System;\nusing System.Collections.Generic;\nusing System.Linq;\n\nnamespace WindroseTrainer.Core\n{\n    /// <summary>\n    /// Engine for training a wind rose model from wind speed and direction data.\n    /// </summary>\n    public class WindroseTrainerEngine\n    {\n        /// <summary>\n        /// Trains a wind rose model by binning wind observations into directional sectors.\n        /// </summary>\n        /// <param name=\"windData\">List of (speed, direction) tuples.</param>\n        /// <param name=\"numSectors\">Number of directional sectors (e.g., 8 for 45-degree bins).</param>\n        /// <returns>A trained WindroseModel containing sector statistics.</returns>\n        public WindroseModel Train(IEnumerable<(double Speed, double Direction)> windData, int numSectors = 8)\n        {\n            if (windData == null || !windData.Any())\n                throw new ArgumentException(\"Wind data must not be null or empty.\");\n            if (numSectors < 1 || numSectors > 360)\n                throw new ArgumentException(\"Number of sectors must be between 1 and 360.\");\n\n            var sectorSize = 360.0 / numSectors;\n            var sectors = new List<WindSector>();\n\n            for (int i = 0; i < numSectors; i++)\n            {\n                double startAngle = i * sectorSize;\n                double endAngle = (i + 1) * sectorSize;\n                sectors.Add(new WindSector\n                {\n                    SectorIndex = i,\n                    StartAngle = startAngle,\n                    EndAngle = endAngle,\n                    Speeds = new List<double>()\n                });\n            }\n\n            foreach (var (speed, direction) in windData)\n            {\n                // Normalize direction to 0-360\n                double normalizedDir = ((direction % 360) + 360) % 360;\n\n                // Find the sector index\n                int sectorIndex = (int)(normalizedDir / sectorSize);\n                if (sectorIndex >= numSectors)\n                    sectorIndex = numSectors - 1;\n\n                sectors[sectorIndex].Speeds.Add(speed);\n            }\n\n            // Compute statistics for each sector\n            foreach (var sector in sectors)\n            {\n                if (sector.Speeds.Count > 0)\n                {\n                    sector.Count = sector.Speeds.Count;\n                    sector.MeanSpeed = sector.Speeds.Average();\n                    sector.StdDevSpeed = CalculateStdDev(sector.Speeds);\n                    sector.MinSpeed = sector.Speeds.Min();\n                    sector.MaxSpeed = sector.Speeds.Max();\n\n                    // Calculate frequency as percentage of total observations\n                    sector.FrequencyPercent = (double)sector.Count / windData.Count() * 100.0;\n                }\n                else\n                {\n                    sector.Count = 0;\n                    sector.MeanSpeed = 0;\n                    sector.StdDevSpeed = 0;\n                    sector.MinSpeed = 0;\n                    sector.MaxSpeed = 0;\n                    sector.FrequencyPercent = 0;\n                }\n            }\n\n            return new WindroseModel\n            {\n                TotalObservations = windData.Count(),\n                NumberOfSectors = numSectors,\n                SectorSize = sectorSize,\n                Sectors = sectors\n            };\n        }\n\n        private double CalculateStdDev(IEnumerable<double> values)\n        {\n            double mean = values.Average();\n            double sumSquares = values.Sum(v => Math.Pow(v - mean, 2));\n            return Math.Sqrt(sumSquares / (values.Count() - 1));\n        }\n    }\n\n    /// <summary>\n    /// Represents a single directional sector in the wind rose.\n    /// </summary>\n    public class WindSector\n    {\n        public int SectorIndex { get; set; }\n        public double StartAngle { get; set; }\n        public double EndAngle { get; set; }\n        public int Count { get; set; }\n        public double MeanSpeed { get; set; }\n        public double StdDevSpeed { get; set; }\n        public double MinSpeed { get; set; }\n        public double MaxSpeed { get; set; }\n        public double FrequencyPercent { get; set; }\n        internal List<double> Speeds { get; set; } // Raw speeds for internal computation\n\n        public override string ToString()\n        {\n            return $\"Sector {SectorIndex}: {StartAngle:F1}°-{EndAngle:F1}° | Count: {Count} | Freq: {FrequencyPercent:F2}% | Mean: {MeanSpeed:F2} m/s | StdDev: {StdDevSpeed:F2}\";\n        }\n    }\n\n    /// <summary>\n    /// Represents the trained wind rose model with all sector data.\n    /// </summary>\n    public class WindroseModel\n    {\n        public int TotalObservations { get; set; }\n        public int NumberOfSectors { get; set; }\n        public double SectorSize { get; set; }\n        public List<WindSector> Sectors { get; set; } = new List<WindSector>();\n\n        /// <summary>\n        /// Serializes the model to JSON format.\n        /// </summary>\n        public string ToJson()\n        {\n            var settings = new Newtonsoft.Json.JsonSerializerSettings\n            {\n                Formatting = Newtonsoft.Json.Formatting.Indented\n            };\n            return Newtonsoft.Json.JsonConvert.SerializeObject(this, settings);\n        }\n\n        public override string ToString()\n        {\n            return string.Join(Environment.NewLine, Sectors.Select(s => s.ToString()));\n        }\n    }\n}\n"
  },
