    "path": "windrose-trainer/Core/WindroseReporter.cs",
    "content": "using System;\nusing System.Linq;\nusing System.Text;\n\nnamespace WindroseTrainer.Core\n{\n    /// <summary>\n    /// Generates human-readable reports from a trained WindroseModel.\n    /// </summary>\n    public class WindroseReporter\n    {\n        /// <summary>\n        /// Generates a detailed text report of the wind rose model.\n        /// </summary>\n        /// <param name=\"model\">The trained wind rose model.</param>\n        /// <returns>A formatted string report.</returns>\n        public string GenerateReport(WindroseModel model)\n        {\n            if (model == null)\n                throw new ArgumentNullException(nameof(model));\n\n            var sb = new StringBuilder();\n            sb.AppendLine(\"Wind Rose Training Report\");\n            sb.AppendLine(\"========================\");\n            sb.AppendLine();\n            sb.AppendLine($\"Total Observations: {model.TotalObservations}\");\n            sb.AppendLine($\"Number of Sectors: {model.NumberOfSectors}\");\n            sb.AppendLine($\"Sector Size: {model.SectorSize:F1}°\");\n            sb.AppendLine();\n\n            // Summary statistics\n            var nonEmptySectors = model.Sectors.Where(s => s.Count > 0).ToList();\n            if (nonEmptySectors.Any())\n            {\n                double overallMeanSpeed = nonEmptySectors.Average(s => s.MeanSpeed);\n                double maxFreq = nonEmptySectors.Max(s => s.FrequencyPercent);\n                var mostFrequentSector = nonEmptySectors.First(s => s.FrequencyPercent == maxFreq);\n\n                sb.AppendLine(\"Summary:\");\n                sb.AppendLine($\"  Overall Mean Wind Speed: {overallMeanSpeed:F2} m/s\");\n                sb.AppendLine($\"  Most Frequent Direction: Sector {mostFrequentSector.SectorIndex} ({mostFrequentSector.StartAngle:F1}°-{mostFrequentSector.EndAngle:F1}°) with {maxFreq:F2}% frequency\");\n                sb.AppendLine();\n            }\n\n            sb.AppendLine(\"Sector Details:\");\n            sb.AppendLine(\"---------------\");\n            foreach (var sector in model.Sectors)\n            {\n                sb.AppendLine(sector.ToString());\n            }\n\n            // Add a simple ASCII wind rose visualization\n            sb.AppendLine();\n            sb.AppendLine(\"Wind Rose Diagram (Frequency %):\");\n            sb.AppendLine(GenerateAsciiWindRose(model));\n\n            return sb.ToString();\n        }\n\n        /// <summary>\n        /// Generates a minimal ASCII representation of the wind rose.\n        /// </summary>\n        private string GenerateAsciiWindRose(WindroseModel model)\n        {\n            var sb = new StringBuilder();\n            double maxFreq = model.Sectors.Max(s => s.FrequencyPercent);\n            int scale = 20; // max bar length\n\n            // Find the center direction (North up)\n            // We'll display sectors in order starting from North\n            var orderedSectors = model.Sectors.OrderBy(s => s.StartAngle).ToList();\n\n            foreach (var sector in orderedSectors)\n            {\n                int barLength = maxFreq > 0 ? (int)(sector.FrequencyPercent / maxFreq * scale) : 0;\n                string bar = new string('#', barLength);\n                sb.AppendLine($\"  {sector.StartAngle,6:F1}°-{sector.EndAngle,6:F1}°: {bar} ({sector.FrequencyPercent,5:F2}%)\");\n            }\n\n            return sb.ToString();\n        }\n    }\n}\n"
  },
