    "path": "windrose-trainer/tests/WindroseTrainerTests.cs",
    "content": "using System;\nusing System.Collections.Generic;\nusing System.Linq;\nusing NUnit.Framework;\nusing WindroseTrainer.Core;\n\nnamespace WindroseTrainer.Tests\n{\n    /// <summary>\n    /// Unit tests for the Windrose Trainer core components.\n    /// </summary>\n    [TestFixture]\n    public class WindroseTrainerTests\n    {\n        [Test]\n        public void Train_WithValidData_ReturnsCorrectNumberOfSectors()\n        {\n            // Arrange\n            var engine = new WindroseTrainerEngine();\n            var data = new List<(double Speed, double Direction)>\n            {\n                (5.0, 0),\n                (3.0, 90),\n                (7.0, 180),\n                (2.0, 270)\n            };\n\n            // Act\n            var model = engine.Train(data, numSectors: 4);\n\n            // Assert\n            Assert.AreEqual(4, model.NumberOfSectors);\n            Assert.AreEqual(4, model.Sectors.Count);\n            Assert.AreEqual(4, model.TotalObservations);\n        }\n\n        [Test]\n        public void Train_WithSingleDirection_BinsCorrectly()\n        {\n            // Arrange\n            var engine = new WindroseTrainerEngine();\n            var data = new List<(double Speed, double Direction)>\n            {\n                (10.0, 45),\n                (12.0, 45),\n                (8.0, 45)\n            };\n\n            // Act\n            var model = engine.Train(data, numSectors: 8);\n\n            // Assert: Sector index for 45° with 8 sectors (45° bin size) is floor(45/45) = 1\n            var sector1 = model.Sectors[1];\n            Assert.AreEqual(3, sector1.Count);\n            Assert.AreEqual(10.0, sector1.MeanSpeed, 1e-6);\n            Assert.AreEqual(100.0, sector1.FrequencyPercent, 1e-6);\n\n            // Other sectors should have zero counts\n            for (int i = 0; i < model.Sectors.Count; i++)\n            {\n                if (i != 1)\n                    Assert.AreEqual(0, model.Sectors[i].Count);\n            }\n        }\n\n        [Test]\n        public void Train_WithEmptyData_ThrowsArgumentException()\n        {\n            // Arrange\n            var engine = new WindroseTrainerEngine();\n            var emptyData = new List<(double Speed, double Direction)>();\n\n            // Act & Assert\n            Assert.Throws<ArgumentException>(() => engine.Train(emptyData));\n        }\n\n        [Test]\n        public void Train_WithInvalidSectorCount_ThrowsArgumentException()\n        {\n            // Arrange\n            var engine = new WindroseTrainerEngine();\n            var data = new List<(double Speed, double Direction)> { (1.0, 0) };\n\n            // Act & Assert\n            Assert.Throws<ArgumentException>(() => engine.Train(data, numSectors: 0));\n            Assert.Throws<ArgumentException>(() => engine.Train(data, numSectors: 361));\n        }\n\n        [Test]\n        public void WindroseModel_ToJson_ProducesValidJson()\n        {\n            // Arrange\n            var engine = new WindroseTrainerEngine();\n            var data = new List<(double Speed, double Direction)>\n            {\n                (5.0, 0),\n                (3.0, 90)\n            };\n            var model = engine.Train(data, numSectors: 4);\n\n            // Act\n            string json = model.ToJson();\n\n            // Assert\n            Assert.IsNotNull(json);\n            Assert.IsTrue(json.Contains(\"TotalObservations\"));\n            Assert.IsTrue(json.Contains(\"Sectors\"));\n            Assert.IsTrue(json.Contains(\"MeanSpeed\"));\n        }\n\n        [Test]\n        public void WindroseReporter_GenerateReport_ReturnsNonEmptyString()\n        {\n            // Arrange\n            var engine = new WindroseTrainerEngine();\n            var data = new List<(double Speed, double Direction)>\n            {\n                (5.0, 0),\n                (3.0, 90),\n                (7.0, 180),\n                (2.0, 270)\n            };\n            var model = engine.Train(data, numSectors: 4);\n            var reporter = new WindroseReporter();\n\n            // Act\n            string report = reporter.GenerateReport(model);\n\n            // Assert\n            Assert.IsFalse(string.IsNullOrEmpty(report));\n            Assert.IsTrue(report.Contains(\"Wind Rose Training Report\"));\n            Assert.IsTrue(report.Contains(\"Sector Details\"));\n        }\n\n        [Test]\n        public void Train_WithData
